// app/(creator)/hub/page.tsx
"use client"

import { useState } from "react"
import { Button } from "@/components/ui/Button"
import { Avatar, Card, Input, SectionLabel, SidebarItem, Tag, Textarea } from "@/components/ui/hubora-ui"
import { cn } from "@/lib/utils"

const TAGS = ["Digital Art", "Illustration", "Procreate", "Colour Theory", "Character Design", "Tutorials"]

export default function CreatorHubPage() {
  const [tags, setTags] = useState(TAGS)
  const [newTag, setNewTag] = useState("")
  const [saved, setSaved] = useState(false)

  const handleSave = () => {
    setSaved(true)
    setTimeout(() => setSaved(false), 2000)
  }

  return (
    <div className="flex min-h-screen bg-[#FAFAFA]">

      <main className="flex-1 px-8 py-8 max-w-4xl">

        {/* Header */}
        <div className="flex items-start justify-between mb-8">
          <div>
            <h1 className="font-display text-[24px] font-bold text-[#0F0F14] tracking-tight">My Hub</h1>
            <p className="font-body text-[13px] text-[#9CA3AF] mt-1">Manage how your hub looks to subscribers</p>
          </div>
          <div className="flex gap-2.5">
            <Button variant="outline" size="md">Preview Hub →</Button>
            <Button variant="primary" size="md" onClick={handleSave}>
              {saved ? "✓ Saved" : "Save Changes"}
            </Button>
          </div>
        </div>

        <div className="flex flex-col gap-6">

          {/* Cover & Avatar */}
          <Card padding="none" className="overflow-hidden">
            <div className="relative">
              {/* Cover */}
              <div className="h-[180px] bg-gradient-to-br from-[#4C1D95] via-[#6C36F5] to-[#A855F7] relative group cursor-pointer">
                <div className="absolute inset-0 bg-black/0 group-hover:bg-black/20 transition-all flex items-center justify-center">
                  <span className="opacity-0 group-hover:opacity-100 transition-all bg-white/20 backdrop-blur-sm text-white font-display font-semibold text-[13px] px-4 py-2 rounded-xl border border-white/30">
                    Change Cover
                  </span>
                </div>
              </div>

              {/* Avatar over cover */}
              <div className="absolute -bottom-8 left-6">
                <div className="relative group cursor-pointer">
                  <div className="w-16 h-16 rounded-2xl bg-gradient-to-br from-[#6C36F5] to-[#A855F7] border-4 border-white shadow-[0_4px_16px_-2px_rgba(108,54,245,0.3)] flex items-center justify-center text-2xl">
                    🎨
                  </div>
                  <div className="absolute inset-0 rounded-2xl bg-black/0 group-hover:bg-black/30 transition-all flex items-center justify-center">
                    <span className="opacity-0 group-hover:opacity-100 text-white text-[10px] font-display font-bold">Edit</span>
                  </div>
                </div>
              </div>
            </div>

            <div className="pt-12 px-6 pb-6">
              <p className="font-body text-[12px] text-[#9CA3AF] mb-1">Click the cover or avatar to upload a new image</p>
            </div>
          </Card>

          {/* Basic Info */}
          <Card padding="lg">
            <h2 className="font-display font-bold text-[16px] text-[#0F0F14] mb-5">Basic Information</h2>
            <div className="flex flex-col gap-4">
              <div className="grid grid-cols-2 gap-4">
                <Input label="Hub Name" type="text" defaultValue="ArtByLola" />
                <Input label="Handle" type="text" defaultValue="artbylola" leftSlot={<span className="text-[13px] font-mono">@</span>} />
              </div>
              <Textarea label="Bio" rows={4} defaultValue="Hi! I'm Lola, a digital artist and illustrator based in Lagos, Nigeria. I've been creating digital art for over 8 years and I'm passionate about teaching others to find their artistic voice." />
              <Input label="Website" type="url" placeholder="https://yourdomain.com" />
            </div>
          </Card>

          {/* Tags */}
          <Card padding="lg">
            <h2 className="font-display font-bold text-[16px] text-[#0F0F14] mb-1">Content Tags</h2>
            <p className="font-body text-[13px] text-[#9CA3AF] mb-5">Help people find your hub. Add up to 8 tags.</p>

            <div className="flex flex-wrap gap-2 mb-4">
              {tags.map(tag => (
                <button
                  key={tag}
                  onClick={() => setTags(tags.filter(t => t !== tag))}
                  className="inline-flex items-center gap-1.5 bg-[#F5F3FF] text-[#6C36F5] border border-[#DDD6FE] text-[12px] font-body font-medium px-3 py-1.5 rounded-full hover:bg-[#EDE9FE] transition-colors group"
                >
                  {tag}
                  <span className="text-[#C4B5FD] group-hover:text-[#6C36F5] text-[10px]">✕</span>
                </button>
              ))}
            </div>

            {tags.length < 8 && (
              <div className="flex gap-2">
                <input
                  value={newTag}
                  onChange={e => setNewTag(e.target.value)}
                  onKeyDown={e => {
                    if (e.key === "Enter" && newTag.trim()) {
                      setTags([...tags, newTag.trim()])
                      setNewTag("")
                    }
                  }}
                  placeholder="Add a tag… (press Enter)"
                  className="flex-1 bg-white border-[1.5px] border-[#E5E7EB] rounded-xl px-4 py-2 text-[13px] font-body outline-none focus:border-[#6C36F5] focus:shadow-[0_0_0_3px_rgba(108,54,245,0.1)] transition-all"
                />
                <Button
                  variant="secondary"
                  size="sm"
                  onClick={() => {
                    if (newTag.trim()) { setTags([...tags, newTag.trim()]); setNewTag("") }
                  }}
                >
                  Add
                </Button>
              </div>
            )}
          </Card>

          {/* Social Links */}
          <Card padding="lg">
            <h2 className="font-display font-bold text-[16px] text-[#0F0F14] mb-5">Social Links</h2>
            <div className="flex flex-col gap-4">
              {[
                { label: "Instagram", placeholder: "@artbylola" },
                { label: "Twitter / X", placeholder: "@artbylola" },
                { label: "TikTok", placeholder: "@artbylola" },
                { label: "YouTube", placeholder: "youtube.com/@artbylola" },
              ].map(s => (
                <Input key={s.label} label={s.label} type="text" placeholder={s.placeholder} />
              ))}
            </div>
          </Card>

          {/* Danger zone */}
          <Card padding="lg" variant="bordered" className="border-[#FEE2E2]">
            <h2 className="font-display font-bold text-[16px] text-[#EF4444] mb-1">Danger Zone</h2>
            <p className="font-body text-[13px] text-[#9CA3AF] mb-4">These actions are permanent and cannot be undone.</p>
            <div className="flex flex-col gap-3">
              <div className="flex items-center justify-between p-4 bg-[#FEF2F2] rounded-2xl">
                <div>
                  <p className="font-display font-semibold text-[13px] text-[#0F0F14]">Pause Hub</p>
                  <p className="font-body text-[12px] text-[#9CA3AF] mt-0.5">Hide your hub from discovery temporarily</p>
                </div>
                <Button variant="outline" size="sm">Pause</Button>
              </div>
              <div className="flex items-center justify-between p-4 bg-[#FEF2F2] rounded-2xl">
                <div>
                  <p className="font-display font-semibold text-[13px] text-[#EF4444]">Delete Hub</p>
                  <p className="font-body text-[12px] text-[#9CA3AF] mt-0.5">Permanently delete your hub and all content</p>
                </div>
                <Button variant="danger" size="sm">Delete</Button>
              </div>
            </div>
          </Card>

        </div>
      </main>
    </div>
  )
}